בטח, הנה דוגמה לתסריט (Script) פשוט בשפת **JavaScript** שיוצר מערך של מספרים אקראיים.

ניתן להריץ את הקוד הזה בדפדפן (Console) או ב-Node.js.

### קוד ב-JavaScript:

```javascript
/**
 * פונקציה ליצירת מערך של מספרים אקראיים
 * @param {number} length - אורך המערך המבוקש
 * @param {number} min - ערך מינימלי (כולל)
 * @param {number} max - ערך מקסימלי (כולל)
 * @returns {number[]} - מערך המספרים שנוצר
 */
function generateRandomArray(length, min, max) {
    const randomArray = [];

    for (let i = 0; i < length; i++) {
        // יצירת מספר אקראי בטווח המבוקש
        const randomNumber = Math.floor(Math.random() * (max - min + 1)) + min;
        randomArray.push(randomNumber);
    }

    return randomArray;
}

// דוגמה לשימוש:
const length = 10; // כמה מספרים נרצה
const min = 1;     // מספר מינימלי
const max = 100;   // מספר מקסימלי

const myNumbers = generateRandomArray(length, min, max);

console.log("המערך שנוצר:");
console.log(myNumbers);
```

---

